     3→namespace Xav\XsaltoPdsFid\ApiClient;
     4→
     5→use Symfony\Component\HttpClient\HttpClient;
     6→use Symfony\Contracts\HttpClient\HttpClientInterface;
     7→
     8→class XsaltoApiClient
     9→{
    10→    private readonly HttpClientInterface $client;
    11→    private ?string $token = null;
    12→
    13→    public function __construct(private readonly string $baseUrl = 'https://pds.xsalto.com')
    14→    {
    15→        $this->client = HttpClient::create();
    16→    }
    17→
    18→    public function login(string $login, string $password): void
    19→    {
    20→        $response = $this->client->request('GET', $this->baseUrl . '/api/login', [
    21→            'query' => ['login' => $login, 'password' => $password],
    22→        ]);
    23→
    24→        $data = $response->toArray();
    25→        $this->token = $data['data']['token'];
    26→    }
    27→
    28→    public function getContacts(int $offset, int $size = 100): array
    29→    {
    30→        if ($this->token === null) {
    31→            throw new \RuntimeException('Not authenticated. Call login() first.');
    32→        }
    33→
    34→        $response = $this->client->request('GET', $this->baseUrl . '/api/contacts', [
    35→            'headers' => ['Authorization' => 'Bearer ' . $this->token],
    36→            'query'   => ['page[size]' => $size, 'page[offset]' => $offset],
    37→        ]);
    38→
    39→        return $response->toArray();
    40→    }
    41→}
