     2→// src/Database/PageTracker.php
     3→namespace Xav\XsaltoPdsFid\Database;
     4→
     5→use Doctrine\DBAL\Connection;
     6→
     7→class PageTracker
     8→{
     9→    public function __construct(private readonly Connection $connection) {}
    10→
    11→    public function isDownloaded(int $offset, int $size): bool
    12→    {
    13→        $count = $this->connection->fetchOne(
    14→            'SELECT COUNT(*) FROM pages WHERE offset = :offset AND size = :size AND status = :status',
    15→            ['offset' => $offset, 'size' => $size, 'status' => 'completed']
    16→        );
    17→        return (int) $count > 0;
    18→    }
    19→
    20→    public function markDownloaded(int $offset, int $size, int $recordCount): void
    21→    {
    22→        $this->connection->executeStatement(
    23→            'INSERT INTO pages (offset, size, downloaded_at, record_count, status)
    24→             VALUES (:offset, :size, NOW(), :record_count, :status)
    25→             ON CONFLICT (offset) DO UPDATE SET
    26→                size          = EXCLUDED.size,
    27→                downloaded_at = NOW(),
    28→                record_count  = EXCLUDED.record_count,
    29→                status        = EXCLUDED.status',
    30→            ['offset' => $offset, 'size' => $size, 'record_count' => $recordCount, 'status' => 'completed']
    31→        );
    32→    }
    33→}
