     2→// src/Importer/ContactImporter.php
     3→namespace Xav\XsaltoPdsFid\Importer;
     4→
     5→use Xav\XsaltoPdsFid\ApiClient\XsaltoApiClient;
     6→use Xav\XsaltoPdsFid\Database\ContactRepository;
     7→use Xav\XsaltoPdsFid\Database\PageTracker;
     8→use Xav\XsaltoPdsFid\Mapper\ContactMapper;
     9→
    10→class ContactImporter
    11→{
    12→    public function __construct(
    13→        private readonly XsaltoApiClient    $apiClient,
    14→        private readonly ContactRepository  $contactRepository,
    15→        private readonly PageTracker        $pageTracker,
    16→        private readonly ContactMapper      $mapper,
    17→        private readonly int                $pageSize = 100,
    18→    ) {}
    19→
    20→    public function import(): void
    21→    {
    22→        $offset = 0;
    23→        $consecutiveSkips = 0;
    24→        $maxConsecutiveSkips = 10; // Stop after 10 pages of all-skipped
    25→
    26→        while (true) {
    27→            if ($this->pageTracker->isDownloaded($offset, $this->pageSize)) {
    28→                echo "Skipping offset={$offset} (already downloaded)\n";
    29→                $offset += $this->pageSize;
    30→                $consecutiveSkips++;
    31→
    32→                if ($consecutiveSkips >= $maxConsecutiveSkips) {
    33→                    echo "Stopping: {$maxConsecutiveSkips} consecutive pages already downloaded.\n";
    34→                    break;
    35→                }
    36→                continue;
    37→            }
    38→
    39→            $consecutiveSkips = 0;
    40→            $response = $this->apiClient->getContacts($offset, $this->pageSize);
    41→            $contacts = $response['data'];
    42→
    43→            if (empty($contacts)) {
    44→                break;
    45→            }
    46→
    47→            foreach ($contacts as $contact) {
    48→                $row = $this->mapper->mapToRow($contact);
    49→                $this->contactRepository->upsert($row);
    50→            }
    51→
    52→            $this->pageTracker->markDownloaded($offset, $this->pageSize, count($contacts));
    53→            echo "Imported offset={$offset}: " . count($contacts) . " contacts\n";
    54→
    55→            $offset += $this->pageSize;
    56→
    57→            if (!isset($response['links']['next'])) {
    58→                break;
    59→            }
    60→        }
    61→    }
    62→}
    63→

