    20→            'id' => '6q85iaor8ayw',
    21→            'attributes' => [
    22→                'LastName'  => 'STONE',
    23→                'FirstName' => 'LUKE',
    24→                'Email'     => 'luke_stone@hotmail.com',
    25→                'Address1'  => '60 Long Garden Walk',
    26→                'Address2'  => null,
    27→                'Address3'  => null,
    28→                'ZipCode'   => 'GU9 7HX',
    29→                'City'      => 'Farnham',
    30→                'Language'  => null,
    31→                'LASTMOVE'  => '2026-03-28 10:13:06',
    32→                'Balance'   => 360,
    33→                'created'   => '2019-03-30 10:08:43',
    34→            ],
    35→            'relationships' => [
    36→                'Country' => ['data' => ['type' => 'countries', 'id' => 'CH']],
    37→                'Resorts' => ['data' => [['type' => 'resorts', 'id' => 'LesGets']]],
    38→                'skiers'  => ['data' => []],
